final class PromoUniversalLinkHandler {
    static let shared = PromoUniversalLinkHandler()

    private let expectedHost = "myapp.com"
    private let expectedPath = "/promo"

    private init() {}

    func register() {
        // Placeholder for any one-time setup if needed.
        // Universal links require Associated Domains entitlement:
        // applinks:myapp.com
        // and an apple-app-site-association file hosted on https://myapp.com/.well-known/apple-app-site-association
    }

    func handle(userActivity: NSUserActivity) {
        guard userActivity.activityType == NSUserActivityTypeBrowsingWeb,
              let url = userActivity.webpageURL else {
            PromoManager.shared.lastResult = "Ignored: Not a web browsing activity."
            return
        }
        handle(url: url)
    }

    func handle(url: URL) {
        let result = process(url: url)
        PromoManager.shared.lastResult = result
    }

    private func process(url: URL) -> String {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return "Rejected: Invalid URL components."
        }

        guard (components.scheme?.lowercased() == "https") else {
            return "Rejected: Scheme must be https."
        }

        guard (components.host?.lowercased() == expectedHost) else {
            return "Rejected: Host must be \(expectedHost)."
        }

        let path = components.percentEncodedPath
        guard path == expectedPath else {
            return "Rejected: Path must be \(expectedPath). Got: \(path)"
        }

        let queryItems = components.queryItems ?? []

        let code = queryItems.first(where: { $0.name.lowercased() == "code" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)
        let discountRaw = queryItems.first(where: { $0.name.lowercased() == "discount" })?.value?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard let promoCode = code, !promoCode.isEmpty else {
            return "Rejected: Missing or empty 'code' parameter."
        }

        guard let discountString = discountRaw, let discount = Int(discountString) else {
            return "Rejected: Missing or invalid 'discount' parameter."
        }

        guard (1...100).contains(discount) else {
            return "Rejected: Discount out of range (1...100). Got: \(discount)"
        }

        PromoManager.shared.applyPromo(code: promoCode, discountPercent: discount)
        return "Applied: code=\(promoCode), discount=\(discount)% to user=\(PromoManager.shared.currentUser.id)"
    }
}

struct UserAccount: Codable, Equatable, Identifiable {
    var id: String
    var activePromoCode: String?
    var activeDiscountPercent: Int?
    var lastPromoAppliedAt: Date?
}

final class PromoManager: ObservableObject {
    static let shared = PromoManager()

    @Published private(set) var currentUser: UserAccount
    @Published var lastResult: String?

    private let storageKeyPrefix = "PromoUniversalLinks.UserAccount."
    private let encoder = JSONEncoder()
    private let decoder = JSONDecoder()

    private init() {
        if let loaded = Self.loadUser(id: "user_001") {
            self.currentUser = loaded
        } else {
            self.currentUser = UserAccount(id: "user_001", activePromoCode: nil, activeDiscountPercent: nil, lastPromoAppliedAt: nil)
            saveUser(self.currentUser)
        }
    }

    func applyPromo(code: String, discountPercent: Int) {
        var user = currentUser
        user.activePromoCode = code
        user.activeDiscountPercent = discountPercent
        user.lastPromoAppliedAt = Date()
        currentUser = user
        saveUser(user)

        MarketingAttributionLogger.log(event: .promoApplied,
                                       payload: [
                                        "userId": user.id,
                                        "code": code,
                                        "discountPercent": "\(discountPercent)",
                                        "timestamp": ISO8601DateFormatter().string(from: user.lastPromoAppliedAt ?? Date())
                                       ])
    }

    func clearPromo(for userId: String) {
        guard currentUser.id == userId else { return }
        var user = currentUser
        user.activePromoCode = nil
        user.activeDiscountPercent = nil
        user.lastPromoAppliedAt = nil
        currentUser = user
        saveUser(user)

        MarketingAttributionLogger.log(event: .promoCleared,
                                       payload: [
                                        "userId": user.id,
                                        "timestamp": ISO8601DateFormatter().string(from: Date())
                                       ])
    }

    private func saveUser(_ user: UserAccount) {
        do {
            let data = try encoder.encode(user)
            UserDefaults.standard.set(data, forKey: storageKeyPrefix + user.id)
        } catch {
            lastResult = "Error saving user: \(error)"
        }
    }

    private static func loadUser(id: String) -> UserAccount? {
        let key = PromoManager.shared.storageKeyPrefix + id
        guard let data = UserDefaults.standard.data(forKey: key) else { return nil }
        do {
            return try PromoManager.shared.decoder.decode(UserAccount.self, from: data)
        } catch {
            return nil
        }
    }
}

